@namespace Lumeo

@{
    var context = new TabsContext(ActiveValue, EventCallback.Factory.Create<string>(this, SetValue), Orientation, Variant, _tabIds, AnimatedIndicator, RenderMode, _activatedValues, SwipeEnabled, SwipeWrap, RegisterContent, UnregisterContent, NavigateBySwipe, _reorderState, Activation)
    {
        IconReveal = IconReveal,
    };
}

<div class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string ActiveValue { get; set; } = "";
    [Parameter] public EventCallback<string> ActiveValueChanged { get; set; }
    [Parameter] public Lumeo.Orientation Orientation { get; set; } = Lumeo.Orientation.Horizontal;
    [Parameter] public TabsVariant Variant { get; set; } = TabsVariant.Default;

    /// <summary>
    /// When true, renders a sliding underline that animates between active
    /// triggers inside each <see cref="TabsList"/>. Default is <c>false</c>
    /// (no underline, original behaviour).
    /// </summary>
    [Parameter] public bool AnimatedIndicator { get; set; }

    /// <summary>
    /// Controls when each <see cref="TabsContent"/> panel is rendered into
    /// the DOM and whether its state survives a tab switch:
    /// <list type="bullet">
    /// <item><see cref="TabsRenderMode.Active"/> (default) — only the active
    /// panel is in the DOM; switching away unmounts it (form inputs, scroll
    /// position and any component state are lost). Lightest footprint.</item>
    /// <item><see cref="TabsRenderMode.Lazy"/> — a panel is rendered the
    /// first time its tab becomes active, then kept in the DOM (hidden) so
    /// its state is preserved on subsequent switches. Like DevExpress
    /// <c>OnDemand</c>.</item>
    /// <item><see cref="TabsRenderMode.Eager"/> — every panel is rendered
    /// immediately; inactive ones are hidden. State always preserved, but
    /// the heaviest initial render. Like DevExpress <c>Always</c>.</item>
    /// </list>
    /// A single <see cref="TabsContent"/> can opt into eager rendering
    /// regardless of this setting via <c>ForceMount="true"</c>.
    /// </summary>
    [Parameter] public TabsRenderMode RenderMode { get; set; } = TabsRenderMode.Active;

    /// <summary>
    /// When true, a horizontal pointer drag (&gt;50 px horizontal, &lt;30 px
    /// vertical) on any <see cref="TabsContent"/> panel switches to the
    /// next or previous tab. Default is <c>false</c> (opt-in).
    /// </summary>
    [Parameter] public bool SwipeEnabled { get; set; }

    /// <summary>
    /// When true, swiping past the last tab wraps around to the first (and
    /// vice-versa). Default is <c>false</c> (no wrap-around at boundaries).
    /// </summary>
    [Parameter] public bool SwipeWrap { get; set; }

    /// <summary>
    /// How arrow-key navigation activates a tab (WAI-ARIA tabs pattern):
    /// <list type="bullet">
    /// <item><see cref="TabsActivation.Automatic"/> (default) — arrow keys move
    /// focus AND activate the focused tab immediately (its panel shows). Best
    /// when switching tabs is cheap.</item>
    /// <item><see cref="TabsActivation.Manual"/> — arrow keys only move focus;
    /// the user presses Enter or Space (or clicks) to activate. Preferred when
    /// activating a tab is expensive (loads data, runs queries).</item>
    /// </list>
    /// </summary>
    [Parameter] public TabsActivation Activation { get; set; } = TabsActivation.Automatic;

    /// <summary>
    /// Icon-tab reveal mode: inactive triggers collapse to icon-only, and the active
    /// trigger smoothly animates its text label into view next to the icon (the label
    /// width grows from 0 → auto via a CSS grid transition, plus a fade). Lets a compact
    /// icon bar stay readable — only the current tab spells itself out. Give each
    /// <see cref="TabsTrigger"/> an <c>IconContent</c> (the always-visible icon) and
    /// <c>ChildContent</c> (the revealed label). Default <c>false</c> (labels always shown).
    /// </summary>
    [Parameter] public bool IconReveal { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Registry: value -> (tabId, panelId, disabled) — maintained by TabsTrigger
    // (registered in OnParametersSet so Disabled changes stay current, removed
    // on dispose so closable/conditional tabs don't leave keyboard ghosts).
    private readonly Dictionary<string, (string TabId, string PanelId, bool Disabled)> _tabIds = new();
    // Set of tab values that have ever been the active tab — drives Lazy mode.
    private readonly HashSet<string> _activatedValues = new();
    // Ordered list of registered TabsContent values — used for swipe navigation.
    private readonly List<string> _contentOrder = new();
    // Shared mutable state for TabsList reordering — owned by TabsList but
    // referenced via the cascading context so triggers can read it.
    private readonly TabsReorderState _reorderState = new();

    private string CssClass => Orientation == Lumeo.Orientation.Vertical
        ? Cx.Merge("flex flex-row", Class)
        : Cx.Merge(Class);

    protected override void OnParametersSet()
    {
        // Track activations so Lazy mode knows which panels to keep mounted.
        if (!string.IsNullOrEmpty(ActiveValue))
            _activatedValues.Add(ActiveValue);
    }

    internal void RegisterContent(string value)
    {
        if (!_contentOrder.Contains(value))
            _contentOrder.Add(value);
    }

    internal void UnregisterContent(string value)
    {
        // Closable/conditionally-removed panels must leave the swipe order,
        // otherwise swipe navigation targets removed tabs (blank panel).
        _contentOrder.Remove(value);
    }

    internal async Task NavigateBySwipe(string direction)
    {
        if (_contentOrder.Count == 0) return;
        var idx = _contentOrder.IndexOf(ActiveValue);
        if (idx < 0) return;

        int next;
        if (direction == "next")
        {
            next = idx + 1;
            if (next >= _contentOrder.Count)
            {
                if (!SwipeWrap) return;
                next = 0;
            }
        }
        else // "prev"
        {
            next = idx - 1;
            if (next < 0)
            {
                if (!SwipeWrap) return;
                next = _contentOrder.Count - 1;
            }
        }

        await SetValue(_contentOrder[next]);
        StateHasChanged();
    }

    private async Task SetValue(string value)
    {
        ActiveValue = value;
        if (!string.IsNullOrEmpty(value))
            _activatedValues.Add(value);
        await ActiveValueChanged.InvokeAsync(value);
    }

    public record TabsContext(
        string ActiveValue,
        EventCallback<string> SetValue,
        Lumeo.Orientation Orientation,
        TabsVariant Variant,
        Dictionary<string, (string TabId, string PanelId, bool Disabled)> TabIds,
        bool AnimatedIndicator,
        TabsRenderMode RenderMode,
        HashSet<string> ActivatedValues,
        bool SwipeEnabled,
        bool SwipeWrap,
        Action<string> RegisterContent,
        Action<string> UnregisterContent,
        Func<string, Task> SwipeNavigate,
        TabsReorderState Reorder,
        TabsActivation Activation = TabsActivation.Automatic)
    {
        public TabsContext(string ActiveValue, EventCallback<string> SetValue, Lumeo.Orientation Orientation = Lumeo.Orientation.Horizontal, TabsVariant Variant = TabsVariant.Default)
            : this(ActiveValue, SetValue, Orientation, Variant, new Dictionary<string, (string, string, bool)>(), false, TabsRenderMode.Active, new HashSet<string>(), false, false, _ => { }, _ => { }, _ => Task.CompletedTask, new TabsReorderState()) { }

        /// <summary>Icon-tab reveal mode (see <see cref="Tabs.IconReveal"/>). Init-only so
        /// the positional constructor above stays source-compatible.</summary>
        public bool IconReveal { get; init; }
    }

    /// <summary>Arrow-key activation mode for tabs. See <see cref="Tabs.Activation"/>.</summary>
    public enum TabsActivation
    {
        /// <summary>Arrow keys move focus and activate the focused tab. Default.</summary>
        Automatic,
        /// <summary>Arrow keys move focus only; Enter/Space (or click) activates.</summary>
        Manual
    }

    /// <summary>
    /// Shared mutable state that flows from <see cref="TabsList"/> down to its
    /// <see cref="TabsTrigger"/> children via the cascading <see cref="TabsContext"/>.
    /// Carries the per-render ordered list of trigger values, the
    /// currently-dragged value (for opacity feedback), and the callbacks that
    /// triggers fire on drag-start / drop. Only meaningful when the enclosing
    /// <see cref="TabsList"/> has <c>Reorderable="true"</c>.
    /// </summary>
    public sealed class TabsReorderState
    {
        public bool Enabled { get; set; }
        public string? DraggingValue { get; set; }
        public List<string> Order { get; } = new();
        public Action<string>? OnDragStart { get; set; }
        public Func<string, Task>? OnDrop { get; set; }
        public Action? OnDragEnd { get; set; }
        public Action<string>? OnDragOver { get; set; }
        public string? DragOverValue { get; set; }
    }

    public enum TabsVariant
    {
        Default,
        Card,
        Pill
    }

    /// <summary>Render strategy for <see cref="TabsContent"/> panels. See
    /// <see cref="Tabs.RenderMode"/> for the semantics of each value.</summary>
    public enum TabsRenderMode
    {
        /// <summary>Only the active panel is in the DOM; switching away unmounts it. Default.</summary>
        Active,
        /// <summary>Panels render on first activation and stay mounted (hidden) afterwards.</summary>
        Lazy,
        /// <summary>All panels render immediately; inactive ones are hidden.</summary>
        Eager
    }
}

@namespace Lumeo
@inject Lumeo.Services.IComponentInteropService Interop
@inject Microsoft.Extensions.Options.IOptions<Lumeo.Services.LumeoGestureOptions> GestureOpts
@implements IAsyncDisposable

@if (ShouldRender_)
{
    <div role="tabpanel"
         id="@PanelId"
         aria-labelledby="@TabId"
         tabindex="0"
         hidden="@(IsActive ? null : "hidden")"
         class="@CssClass"
         @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@code {
    [CascadingParameter] public Tabs.TabsContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";

    /// <summary>
    /// When true, this panel is always rendered into the DOM (hidden when
    /// inactive), regardless of the parent <see cref="Tabs.RenderMode"/>.
    /// Use for panels whose state must survive every tab switch — e.g. a
    /// half-filled form — while leaving the rest of the tab set on the
    /// lighter default mode.
    /// </summary>
    [Parameter] public bool ForceMount { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsActive => Context.ActiveValue == Value;
    private bool _swipeAttached;

    // Decide whether this panel's <div> exists in the DOM at all.
    //   Active mode  → only when this tab is the active one
    //   Lazy mode    → once this tab has ever been activated (or ForceMount)
    //   Eager mode   → always (or ForceMount)
    private bool ShouldRender_
    {
        get
        {
            if (ForceMount) return true;
            return Context.RenderMode switch
            {
                Tabs.TabsRenderMode.Eager => true,
                Tabs.TabsRenderMode.Lazy  => IsActive || Context.ActivatedValues.Contains(Value),
                _                          => IsActive
            };
        }
    }

    private string PanelId => Context.TabIds.TryGetValue(Value, out var ids) ? ids.PanelId : $"tabpanel-{Value}";
    private string TabId => Context.TabIds.TryGetValue(Value, out var ids) ? ids.TabId : $"tab-{Value}";

    private string CssClass => Context.SwipeEnabled
        ? Cx.Merge("mt-2 focus-visible:outline-none touch-pan-y", Class)
        : Cx.Merge("mt-2 focus-visible:outline-none", Class);

    protected override void OnInitialized()
    {
        // Register this panel's value in the parent's ordered list.
        Context.RegisterContent(Value);
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!Context.SwipeEnabled) return;

        // Re-attach whenever this panel transitions from inactive → active.
        // In Active render mode the <div> is removed from the DOM when the tab
        // becomes inactive, so every time it reappears it is a fresh element
        // with no JS listeners — we must re-register each time.
        var shouldAttach = IsActive;
        if (shouldAttach && !_swipeAttached)
        {
            _swipeAttached = true;
            try
            {
                await Interop.RegisterTabSwipe(PanelId, Context.SwipeWrap, async direction =>
                {
                    // Navigate via the parent Tabs component's method through the context callback.
                    // The context carries a delegate that resolves to Tabs.NavigateBySwipe.
                    await Context.SwipeNavigate(direction);
                }, GestureOpts.Value.SwipeThresholdPx, GestureOpts.Value.VerticalDeadZonePx);
            }
            catch (JSDisconnectedException) { _swipeAttached = false; }
            catch (InvalidOperationException) { _swipeAttached = false; } // JS unavailable during prerender
        }
        else if (!shouldAttach && _swipeAttached)
        {
            _swipeAttached = false;
            try { await Interop.UnregisterTabSwipe(PanelId); }
            catch (JSDisconnectedException) { }
        }
    }

    public async ValueTask DisposeAsync()
    {
        // Leave the swipe-navigation order — otherwise swipes target removed
        // tabs and land on a blank panel.
        Context.UnregisterContent(Value);

        if (!_swipeAttached) return;
        try
        {
            await Interop.UnregisterTabSwipe(PanelId);
        }
        catch (JSDisconnectedException) { }
    }
}

namespace Lumeo;

/// <summary>
/// JSON-serializable snapshot of a <see cref="TabsList"/>'s current tab order.
/// Used to persist user-reordered tabs across sessions in tandem with
/// <see cref="TabsList.SavedLayout"/> and <see cref="TabsList.OnLayoutChanged"/>.
/// </summary>
/// <param name="Order">
/// The ordered list of <see cref="TabsTrigger.Value"/> identifiers, in the
/// order they should appear in the list.
/// </param>
/// <remarks>
/// The library never mutates the consumer's backing collection. The consumer
/// is responsible for:
/// <list type="bullet">
/// <item>Persisting the <see cref="TabsLayout"/> received from
/// <see cref="TabsList.OnLayoutChanged"/> (e.g. to local storage or a server).</item>
/// <item>Re-ordering its backing collection from <see cref="Order"/> on
/// initialisation, before passing it to <see cref="TabsList.SavedLayout"/>.</item>
/// </list>
/// This mirrors the existing reorder model where <c>OnReorder</c> reports the
/// drag without applying it — the consumer remains the source of truth.
/// </remarks>
public sealed record TabsLayout(IReadOnlyList<string> Order);

@namespace Lumeo
@inject Lumeo.Services.IComponentInteropService Interop
@inject Lumeo.Services.ThemeService Theme
@implements IAsyncDisposable

@{
    // When reorderable, wire the shared TabsReorderState that flows to each
    // TabsTrigger via the cascading TabsContext, and reset the per-render
    // ordered list so triggers can append themselves in render order.
    if (Context is not null)
    {
        Context.Reorder.Enabled = Reorderable;
        if (Reorderable)
        {
            Context.Reorder.Order.Clear();
            Context.Reorder.OnDragStart = HandleDragStart;
            Context.Reorder.OnDrop = HandleDrop;
            Context.Reorder.OnDragEnd = HandleDragEnd;
            Context.Reorder.OnDragOver = HandleDragOver;
        }
        else
        {
            Context.Reorder.DraggingValue = null;
            Context.Reorder.DragOverValue = null;
        }
    }
}

@if (Scrollable)
{
    <div class="relative flex items-center @(IsVertical ? "flex-col" : "")">
        @if (ShowArrows && _canScrollStart)
        {
            <button type="button" tabindex="-1" aria-hidden="true"
                    class="@ArrowClass" @onclick="ScrollToStart">
                <Blazicon Svg="@StartArrowIcon" class="h-4 w-4" />
            </button>
        }
        <div class="overflow-hidden flex-1 min-w-0">
            <div id="@_listId" role="tablist" aria-orientation="@OrientationStr" class="@CssClass overflow-x-auto scrollbar-none" style="@IndicatorStyle" data-sliding-pill="@(UsePillIndicator ? "true" : null)" @attributes="AdditionalAttributes">
                @ChildContent
                @if (TrailingContent is not null)
                {
                    @TrailingContent
                }
                @if (RenderIndicator)
                {
                    <span aria-hidden="true" class="@IndicatorClass" data-ready="@(_indicatorReady ? "true" : "false")"></span>
                }
            </div>
        </div>
        @if (ShowArrows && _canScrollEnd)
        {
            <button type="button" tabindex="-1" aria-hidden="true"
                    class="@ArrowClass" @onclick="ScrollToEnd">
                <Blazicon Svg="@EndArrowIcon" class="h-4 w-4" />
            </button>
        }
    </div>
}
else
{
    <div id="@_listId" role="tablist" aria-orientation="@OrientationStr" class="@CssClass" style="@IndicatorStyle" data-sliding-pill="@(UsePillIndicator ? "true" : null)" @attributes="AdditionalAttributes">
        @ChildContent
        @if (TrailingContent is not null)
        {
            @TrailingContent
        }
        @if (RenderIndicator)
        {
            <span aria-hidden="true" class="@IndicatorClass" data-ready="@(_indicatorReady ? "true" : "false")"></span>
        }
    </div>
}

@code {
    [CascadingParameter] public Tabs.TabsContext? Context { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public RenderFragment? TrailingContent { get; set; }
    [Parameter] public bool Scrollable { get; set; }

    /// <summary>
    /// When true (and <see cref="Scrollable"/>), shows chevron buttons at the
    /// start/end of the list that scroll it when the tabs overflow. The arrows
    /// auto-hide at the scroll boundaries (and entirely when nothing
    /// overflows). Default true — a scrollable list with no way to reach
    /// off-screen tabs by mouse is a usability gap (#239). Set false to keep
    /// the bare scroll/swipe affordance.
    /// </summary>
    [Parameter] public bool Arrows { get; set; } = true;

    /// <summary>
    /// When true, each enabled <see cref="TabsTrigger"/> becomes draggable
    /// (HTML5 drag-and-drop on desktop, touch drag on mobile). On a successful
    /// reorder the library raises <see cref="OnReorder"/> with the from/to
    /// indices and moved value — <b>the library does NOT mutate the order</b>.
    /// The consumer's handler is responsible for updating the underlying
    /// collection and re-rendering.
    /// </summary>
    /// <example>
    /// <code>
    /// &lt;TabsList Reorderable="true" OnReorder="HandleReorder"&gt;
    ///     @foreach (var t in _tabs)
    ///     {
    ///         &lt;TabsTrigger @key="t.Value" Value="@t.Value"&gt;@t.Label&lt;/TabsTrigger&gt;
    ///     }
    /// &lt;/TabsList&gt;
    ///
    /// @code {
    ///     private void HandleReorder(TabsReorderEventArgs e)
    ///     {
    ///         var moved = _tabs[e.FromIndex];
    ///         _tabs.RemoveAt(e.FromIndex);
    ///         _tabs.Insert(e.ToIndex, moved);
    ///     }
    /// }
    /// </code>
    /// </example>
    [Parameter] public bool Reorderable { get; set; }

    /// <summary>
    /// Fires when the user drops a dragged <see cref="TabsTrigger"/> on a new
    /// position. Only meaningful when <see cref="Reorderable"/> is true.
    /// </summary>
    [Parameter] public EventCallback<TabsReorderEventArgs> OnReorder { get; set; }

    /// <summary>
    /// Optional previously-persisted tab ordering. The library does not mutate
    /// the consumer's backing collection on its own — pass this to your parent
    /// component on init and apply <see cref="TabsLayout.Order"/> to your
    /// collection before rendering. Mirrors DataGrid's <c>SavedLayout</c>
    /// parameter and pairs with <see cref="OnLayoutChanged"/> to round-trip
    /// the order through your storage of choice.
    /// </summary>
    /// <example>
    /// <code>
    /// // On init: read the persisted layout and re-order the backing list.
    /// protected override void OnInitialized()
    /// {
    ///     _savedLayout = LoadFromStorage();
    ///     if (_savedLayout is not null)
    ///         _tabs = _tabs.OrderBy(t => _savedLayout.Order.IndexOf(t.Value)).ToList();
    /// }
    ///
    /// // On change: persist the new layout so it survives the next load.
    /// private Task HandleLayoutChanged(TabsLayout layout)
    /// {
    ///     _savedLayout = layout;
    ///     return SaveToStorage(layout);
    /// }
    /// </code>
    /// </example>
    [Parameter] public TabsLayout? SavedLayout { get; set; }

    /// <summary>
    /// Fires immediately after each successful reorder with the post-drop tab
    /// order, so the consumer can persist it (e.g. to local storage). The
    /// snapshot reflects the order the consumer's collection will have once
    /// it applies the corresponding <see cref="OnReorder"/>. Only meaningful
    /// when <see cref="Reorderable"/> is true. Pairs with
    /// <see cref="SavedLayout"/> to round-trip the order through storage.
    /// </summary>
    [Parameter] public EventCallback<TabsLayout> OnLayoutChanged { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _listId = LumeoIds.New("tabslist");
    private double _indicatorX;
    private double _indicatorW;
    private bool _indicatorReady;
    private string? _lastMeasuredValue;
    private bool _touchRegistered;
    private bool _overflowRegistered;
    private bool _canScrollStart;
    private bool _canScrollEnd;

    private bool IsVertical => Context?.Orientation == Lumeo.Orientation.Vertical;
    private string OrientationStr => IsVertical ? "vertical" : "horizontal";
    private Tabs.TabsVariant CurrentVariant => Context?.Variant ?? Tabs.TabsVariant.Default;

    private bool ShowArrows => Scrollable && Arrows;

    // Chevrons point along the scroll axis: horizontal lists scroll left/right,
    // vertical lists scroll up/down. RTL flips the horizontal pair so "start"
    // always points toward the visual beginning.
    private Blazicons.SvgIcon StartArrowIcon => IsVertical
        ? Blazicons.Lucide.ChevronUp
        : (Theme.CurrentDirection == LayoutDirection.Rtl ? Blazicons.Lucide.ChevronRight : Blazicons.Lucide.ChevronLeft);
    private Blazicons.SvgIcon EndArrowIcon => IsVertical
        ? Blazicons.Lucide.ChevronDown
        : (Theme.CurrentDirection == LayoutDirection.Rtl ? Blazicons.Lucide.ChevronLeft : Blazicons.Lucide.ChevronRight);

    private string ArrowClass =>
        "z-10 flex shrink-0 items-center justify-center rounded-md text-muted-foreground hover:text-foreground cursor-pointer transition-colors h-8 w-6";

    private bool RenderIndicator => Context?.AnimatedIndicator == true && !IsVertical;

    // Default and Pill variants render a background pill that slides; Card uses an underline.
    private bool UsePillIndicator => RenderIndicator && CurrentVariant != Tabs.TabsVariant.Card;

    private string IndicatorClass => UsePillIndicator ? "lumeo-tabs-indicator" : "lumeo-tabs-underline";

    private string? IndicatorStyle => RenderIndicator
        ? $"--lumeo-tabs-indicator-x: {_indicatorX.ToString(System.Globalization.CultureInfo.InvariantCulture)}px; --lumeo-tabs-indicator-w: {_indicatorW.ToString(System.Globalization.CultureInfo.InvariantCulture)}px;"
        : null;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Reorderable && firstRender && !_touchRegistered)
        {
            try
            {
                await Interop.RegisterSortableTouch(_listId, HandleTouchDrop);
                _touchRegistered = true;
            }
            catch (JSDisconnectedException) { }
            catch (InvalidOperationException) { } // prerender
        }

        if (ShowArrows && !_overflowRegistered)
        {
            try
            {
                await Interop.RegisterTabsOverflow(_listId, OnOverflowChange);
                _overflowRegistered = true;
            }
            catch (JSDisconnectedException) { }
            catch (InvalidOperationException) { } // prerender
        }
        else if (!ShowArrows && _overflowRegistered)
        {
            // Scrollable/Arrows toggled off after first render — tear the observer
            // down and clear the stale scroll-state so the arrows disappear.
            try
            {
                await Interop.UnregisterTabsOverflow(_listId);
                _overflowRegistered = false;
                _canScrollStart = false;
                _canScrollEnd = false;
            }
            catch (JSDisconnectedException) { }
            catch (InvalidOperationException) { } // prerender
        }

        if (!RenderIndicator || Context is null) return;

        var active = Context.ActiveValue;
        if (string.IsNullOrEmpty(active)) return;
        if (!Context.TabIds.TryGetValue(active, out var ids)) return;
        if (_lastMeasuredValue == active && _indicatorReady) return;

        ComponentInteropService.TabMeasurement? measurement;
        try
        {
            measurement = await Interop.TabsMeasure(ids.TabId);
        }
        catch (JSDisconnectedException) { return; }
        catch (InvalidOperationException) { return; } // thrown during prerender when JS is unavailable
        if (measurement is null) return;

        var changed = Math.Abs(measurement.X - _indicatorX) > 0.5
                     || Math.Abs(measurement.Width - _indicatorW) > 0.5
                     || !_indicatorReady;

        _indicatorX = measurement.X;
        _indicatorW = measurement.Width;
        _indicatorReady = true;
        _lastMeasuredValue = active;

        if (changed)
        {
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_touchRegistered)
        {
            try { await Interop.UnregisterSortableTouch(_listId); }
            catch (JSDisconnectedException) { }
            _touchRegistered = false;
        }
        if (_overflowRegistered)
        {
            try { await Interop.UnregisterTabsOverflow(_listId); }
            catch (JSDisconnectedException) { }
            _overflowRegistered = false;
        }
    }

    // JS reports whether the list can still scroll toward the start / end; drive
    // the arrow visibility from it.
    private Task OnOverflowChange(bool canScrollStart, bool canScrollEnd)
    {
        if (_canScrollStart == canScrollStart && _canScrollEnd == canScrollEnd) return Task.CompletedTask;
        _canScrollStart = canScrollStart;
        _canScrollEnd = canScrollEnd;
        StateHasChanged();
        return Task.CompletedTask;
    }

    // Each arrow nudges the list by ~75% of its visible extent toward that edge.
    private async Task ScrollToStart()
    {
        try { await Interop.TabsScrollBy(_listId, -ScrollChunkPx, !IsVertical); }
        catch (JSDisconnectedException) { }
    }

    private async Task ScrollToEnd()
    {
        try { await Interop.TabsScrollBy(_listId, ScrollChunkPx, !IsVertical); }
        catch (JSDisconnectedException) { }
    }

    private const double ScrollChunkPx = 200;

    private void HandleDragStart(string value)
    {
        if (Context is null) return;
        Context.Reorder.DraggingValue = value;
        StateHasChanged();
    }

    private void HandleDragOver(string value)
    {
        if (Context is null) return;
        if (Context.Reorder.DragOverValue == value) return;
        Context.Reorder.DragOverValue = value;
        StateHasChanged();
    }

    private void HandleDragEnd()
    {
        if (Context is null) return;
        Context.Reorder.DraggingValue = null;
        Context.Reorder.DragOverValue = null;
        StateHasChanged();
    }

    private async Task HandleDrop(string targetValue)
    {
        if (Context is null) return;
        var from = Context.Reorder.DraggingValue;
        Context.Reorder.DraggingValue = null;
        Context.Reorder.DragOverValue = null;

        if (string.IsNullOrEmpty(from) || from == targetValue)
        {
            StateHasChanged();
            return;
        }

        var order = Context.Reorder.Order;
        var fromIndex = order.IndexOf(from);
        var toIndex = order.IndexOf(targetValue);
        if (fromIndex < 0 || toIndex < 0)
        {
            StateHasChanged();
            return;
        }

        StateHasChanged();
        await OnReorder.InvokeAsync(new TabsReorderEventArgs(fromIndex, toIndex, from));
        await NotifyLayoutChangedAsync(fromIndex, toIndex);
    }

    private async Task HandleTouchDrop(int source, int target)
    {
        if (Context is null) return;
        var order = Context.Reorder.Order;
        if (source < 0 || target < 0 || source >= order.Count || target >= order.Count || source == target) return;
        var moved = order[source];
        await InvokeAsync(async () =>
        {
            await OnReorder.InvokeAsync(new TabsReorderEventArgs(source, target, moved));
            await NotifyLayoutChangedAsync(source, target);
        });
    }

    // Computes the post-drop tab order (without mutating the live Order list,
    // which is re-populated per-render by TabsTrigger) and raises
    // OnLayoutChanged so the consumer can persist it.
    private async Task NotifyLayoutChangedAsync(int fromIndex, int toIndex)
    {
        if (!OnLayoutChanged.HasDelegate || Context is null) return;
        var live = Context.Reorder.Order;
        if (fromIndex < 0 || toIndex < 0 || fromIndex >= live.Count || toIndex >= live.Count) return;

        var snapshot = new List<string>(live);
        var moved = snapshot[fromIndex];
        snapshot.RemoveAt(fromIndex);
        snapshot.Insert(toIndex, moved);
        await OnLayoutChanged.InvokeAsync(new TabsLayout(snapshot));
    }

    private string CssClass
    {
        get
        {
            var baseClasses = CurrentVariant switch
            {
                Tabs.TabsVariant.Card => IsVertical
                    ? "flex flex-col h-auto w-auto items-stretch justify-start border-e border-border/40 text-muted-foreground"
                    // items-END, not center: the active card pulls itself onto
                    // the list's bottom border (-mb-px); centered tabs floated
                    // above the border line with a visible gap, so the "card"
                    // looked detached from its baseline.
                    : "inline-flex h-10 items-end justify-center border-b border-border/40 text-muted-foreground",
                Tabs.TabsVariant.Pill => IsVertical
                    ? "flex flex-col h-auto w-auto items-stretch justify-start gap-1 text-muted-foreground"
                    : "inline-flex h-10 items-center justify-center gap-1 text-muted-foreground",
                _ => IsVertical
                    ? "flex flex-col h-auto w-auto items-stretch justify-start rounded-lg bg-muted p-1 text-muted-foreground"
                    : "inline-flex h-9 items-center justify-center rounded-lg bg-muted p-1 text-muted-foreground"
            };
            var indicatorWrapper = RenderIndicator ? "relative lumeo-tabs-list" : null;
            return Cx.Merge(baseClasses, indicatorWrapper, Class);
        }
    }
}

namespace Lumeo;

/// <summary>
/// Payload for <see cref="TabsList.OnReorder"/>. Raised after a successful
/// drag-and-drop reorder of <see cref="TabsTrigger"/> headers when the
/// enclosing <see cref="TabsList"/> has <c>Reorderable="true"</c>.
/// </summary>
/// <param name="FromIndex">Zero-based position of the moved trigger before the drop.</param>
/// <param name="ToIndex">Zero-based position the trigger was dropped onto.</param>
/// <param name="MovedTabValue">The <c>Value</c> of the trigger that was moved.</param>
/// <remarks>
/// The library does <b>not</b> mutate the underlying tab collection — the
/// consumer's handler is expected to update its own data source and trigger a
/// re-render so the new order takes effect.
/// </remarks>
public sealed record TabsReorderEventArgs(int FromIndex, int ToIndex, string MovedTabValue);

@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@{
    // Register this trigger's position in the per-render ordered list used
    // for drag-reorder. Order list is reset by TabsList at the start of each
    // render; triggers append themselves here, so list order matches DOM order.
    var reorderState = Context.Reorder;
    var reorderActive = reorderState.Enabled && !Disabled;
    if (reorderState.Enabled && !reorderState.Order.Contains(Value))
    {
        reorderState.Order.Add(Value);
    }
}

<button type="button"
        id="@_tabId"
        role="tab"
        aria-selected="@IsActive.ToString().ToLower()"
        aria-disabled="@(Disabled ? "true" : null)"
        aria-controls="@_panelId"
        tabindex="@(Disabled ? -1 : IsActive ? 0 : -1)"
        class="@CssClass"
        draggable="@(reorderActive ? "true" : null)"
        data-sortable-item="@(reorderActive ? "" : null)"
        data-sortable-index="@(reorderActive ? reorderState.Order.IndexOf(Value).ToString() : null)"
        @ondragstart="HandleDragStart"
        @ondragover="HandleDragOver"
        @ondragover:preventDefault="@reorderActive"
        @ondrop="HandleDrop"
        @ondrop:preventDefault="@reorderActive"
        @ondragend="HandleDragEnd"
        @onclick="Activate"
        @onkeydown="HandleKeyDown"
        @attributes="AdditionalAttributes">
    @if (IconContent is not null)
    {
        <span class="inline-flex shrink-0">@IconContent</span>
    }
    @if (Context.IconReveal)
    {
        @* Icon-reveal: the label collapses to 0 width when inactive and animates open
           on the active tab (CSS grid 0fr→1fr + fade). The inner span clips the text
           during the transition; it stays in the DOM so it's always reachable to AT. *@
        <span class="lumeo-tab-label@(IsActive ? " lumeo-tab-label-open" : "")"><span>@ChildContent</span></span>
    }
    else
    {
        @ChildContent
    }
    @if (TrailingContent is not null)
    {
        <span class="inline-flex shrink-0">@TrailingContent</span>
    }
    @if (IsClosable)
    {
        <span class="ms-1 inline-flex items-center justify-center rounded-sm cursor-pointer opacity-70 hover:opacity-100 transition-opacity h-11 w-11 -my-2 sm:h-4 sm:w-4 sm:my-0 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
              @onclick="HandleClose" @onclick:stopPropagation="true"
              role="button" aria-label="@L["Tabs.CloseTab"]">
            <Blazicon Svg="Lucide.X" class="h-3 w-3" />
        </span>
    }
</button>

@inject IComponentInteropService Interop
@inject ThemeService Theme

@code {
    [CascadingParameter] public Tabs.TabsContext Context { get; set; } = default!;
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Icon slot. Named <c>IconContent</c> to avoid shadowing the <c>&lt;Icon&gt;</c> component.</summary>
    [Parameter] public RenderFragment? IconContent { get; set; }

    [Parameter] public RenderFragment? TrailingContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public bool IsClosable { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _tabId = LumeoIds.New("tab");
    private readonly string _panelId = LumeoIds.New("tabpanel");
    private string? _registeredValue;

    private bool IsActive => Context.ActiveValue == Value;
    private Tabs.TabsVariant CurrentVariant => Context.Variant;

    protected override void OnParametersSet()
    {
        // Registered every parameter set (idempotent dictionary write) so a
        // changed Disabled flag stays current for sibling arrow-key navigation,
        // and a changed Value doesn't orphan the old key. Ownership guard on
        // removal: positional diffing can re-key THIS instance while a sibling
        // already took over the old value — only remove entries we still own.
        if (_registeredValue is not null && _registeredValue != Value
            && Context.TabIds.TryGetValue(_registeredValue, out var old) && old.TabId == _tabId)
        {
            Context.TabIds.Remove(_registeredValue);
        }
        Context.TabIds[Value] = (_tabId, _panelId, Disabled);
        _registeredValue = Value;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Re-register whenever Orientation changes (not just firstRender): a
        // first-render-only registration kept suppressing the original axis
        // after a runtime orientation switch, so a now-vertical tablist still
        // scrolled the page on Up/Down while Left/Right stayed prevented
        // (Codex P2). Key-selective preventDefault in JS also replaced the
        // former render-time _preventKey flag, which lagged one event behind.
        if (_pdRegistered && _registeredOrientation == Context.Orientation) return;
        try
        {
            var keys = Context.Orientation == Lumeo.Orientation.Horizontal
                ? new[] { "ArrowLeft", "ArrowRight", "Home", "End" }
                : new[] { "ArrowUp", "ArrowDown", "Home", "End" };
            await Interop.RegisterPreventDefaultKeys(
                _tabId,
                keys.Select(k => new PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
            _registeredOrientation = Context.Orientation;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private bool _pdRegistered;
    private Lumeo.Orientation? _registeredOrientation;

    public async ValueTask DisposeAsync()
    {
        // Closable/conditional tabs must leave the registry, otherwise arrow
        // navigation still targets them (focus call on a removed element) and
        // Home/End resolve to ghosts. Ownership guard: when positional diffing
        // re-keys a surviving sibling onto our old value BEFORE we dispose,
        // the entry belongs to that sibling now — removing it would delete a
        // live tab from keyboard navigation.
        if (_registeredValue is not null
            && Context.TabIds.TryGetValue(_registeredValue, out var ids) && ids.TabId == _tabId)
        {
            Context.TabIds.Remove(_registeredValue);
        }
        Context.Reorder.Order.Remove(Value);
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_tabId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    private string CssClass
    {
        get
        {
            var disabledClasses = Disabled ? "opacity-50 cursor-not-allowed pointer-events-none" : "";
            // Card variant: EVERY card tab carries the same box metrics — the
            // inactive ones just render the border transparent. When only the
            // active tab had a real border, switching tabs grew the new tab by
            // 2px and shrank the old one, and the base `transition-all`
            // animated that reflow: the whole row visibly flickered on every
            // switch. With constant geometry, activation only swaps colors.
            // Axis-aware: the seam side (bottom for horizontal, right for
            // vertical) is open and squared so the active card fuses with the
            // list's edge border; base rounded-md must not survive there.
            var isVerticalTabs = Context.Orientation == Lumeo.Orientation.Vertical;
            var cardGeometry = isVerticalTabs
                ? "rounded-s-lg rounded-e-none border border-e-0 -me-px"
                : "rounded-t-lg rounded-b-none border border-b-0 -mb-px";
            var variantClasses = CurrentVariant switch
            {
                Tabs.TabsVariant.Card => Cx.Join(
                    cardGeometry,
                    IsActive
                        ? "border-border/40 bg-card text-foreground"
                        : "border-transparent text-muted-foreground hover:text-foreground"),
                Tabs.TabsVariant.Pill => IsActive
                    ? "rounded-full bg-primary text-primary-foreground"
                    : "text-muted-foreground hover:bg-muted/50 rounded-full",
                _ => IsActive
                    ? "bg-background text-foreground shadow"
                    : ""
            };

            var reorderState = Context.Reorder;
            var reorderActive = reorderState.Enabled && !Disabled;
            var isDragging = reorderActive && reorderState.DraggingValue == Value;
            var isDragOver = reorderActive && reorderState.DragOverValue == Value && reorderState.DraggingValue != Value;

            // Smooth transform transitions animate any sibling shifts after drop.
            // Only enable touch-friendly grab cursor when this trigger can be dragged.
            var reorderClasses = reorderActive
                ? "transition-transform duration-150 ease-out cursor-grab active:cursor-grabbing select-none"
                : "";
            if (isDragging) reorderClasses += " opacity-50";
            if (isDragOver) reorderClasses += Context.Orientation == Lumeo.Orientation.Vertical
                ? " ring-2 ring-primary ring-offset-0"
                : " ring-2 ring-primary ring-offset-0";

            // In IconReveal mode the label span owns its spacing via margin-left, so
            // drop the inter-child gap (otherwise an icon-only inactive tab keeps a
            // trailing 0.5rem gap and the icon sits off-centre).
            return Cx.Merge("inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md", PadClass, "text-sm font-medium cursor-pointer transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 disabled:cursor-not-allowed", variantClasses, disabledClasses, reorderClasses, Cx.When(Context.IconReveal, "gap-0"), Class);
        }
    }

    // Trigger padding tracks the ambient DensityScope; Comfortable reproduces
    // the historical `px-3 py-1.5`.
    private string PadClass => Density switch
    {
        Lumeo.Density.Compact => "px-2 py-1",
        Lumeo.Density.Spacious => "px-4 py-2",
        _ => "px-3 py-1.5"
    };

    private async Task Activate()
    {
        if (Disabled) return;
        // Don't activate when finishing a drag (a click event fires after dragend).
        if (Context.Reorder.Enabled && Context.Reorder.DraggingValue == Value) return;
        await Context.SetValue.InvokeAsync(Value);
    }

    private void HandleDragStart()
    {
        if (Context.Reorder.Enabled && !Disabled)
            Context.Reorder.OnDragStart?.Invoke(Value);
    }

    private void HandleDragOver()
    {
        // Disabled triggers are not valid drop targets — skip both the visual
        // hint and the over-tracking so a dragged item passes through.
        if (Context.Reorder.Enabled && !Disabled && Context.Reorder.DraggingValue is not null)
            Context.Reorder.OnDragOver?.Invoke(Value);
    }

    private async Task HandleDrop()
    {
        if (Context.Reorder.Enabled && !Disabled && Context.Reorder.OnDrop is not null)
            await Context.Reorder.OnDrop.Invoke(Value);
    }

    private void HandleDragEnd()
    {
        // Always fire so the source clears its state even if dropped outside.
        if (Context.Reorder.Enabled)
            Context.Reorder.OnDragEnd?.Invoke();
    }

    private async Task HandleClose()
    {
        await OnClose.InvokeAsync();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (Disabled) return;

        // WAI-ARIA tabs: Delete closes a closable tab from the keyboard (the
        // visual close affordance is a non-focusable span — nesting a real
        // button inside the tab button would be invalid HTML).
        if (e.Key == "Delete" && IsClosable)
        {
            // Capture the focus target BEFORE closing: this tab's button is about to
            // vanish, so move focus to the next enabled tab (or the previous if this
            // was the last) rather than dropping it to <body> (WCAG 2.4.3). The
            // neighbour's id is stable across the removal re-render, so focusing it
            // after the close is robust regardless of render timing.
            var tabKeys = Context.TabIds.Keys.ToList();
            var tabIdx = tabKeys.IndexOf(Value);
            string? neighbourTabId = null;
            for (var i = tabIdx + 1; i < tabKeys.Count && neighbourTabId is null; i++)
                if (!IsTabDisabled(tabKeys[i]) && Context.TabIds.TryGetValue(tabKeys[i], out var n)) neighbourTabId = n.TabId;
            for (var i = tabIdx - 1; i >= 0 && neighbourTabId is null; i--)
                if (!IsTabDisabled(tabKeys[i]) && Context.TabIds.TryGetValue(tabKeys[i], out var n)) neighbourTabId = n.TabId;

            await HandleClose();

            if (neighbourTabId is not null)
            {
                try { await Interop.FocusElement(neighbourTabId); }
                catch (Microsoft.JSInterop.JSDisconnectedException) { }
            }
            return;
        }

        var isHorizontal = Context.Orientation == Lumeo.Orientation.Horizontal;
        var isRtl = Theme.CurrentDirection == LayoutDirection.Rtl;
        var keys = Context.TabIds.Keys.ToList();
        var idx = keys.IndexOf(Value);

        // In RTL, ArrowLeft/Right are swapped for horizontal tabs so they follow visual flow.
        var (hBack, hForward) = (isHorizontal && isRtl) ? ("ArrowRight", "ArrowLeft") : ("ArrowLeft", "ArrowRight");

        string? nextValue = null;
        if (isHorizontal)
        {
            if (e.Key == hForward) nextValue = FindNextEnabledTab(keys, idx, 1);
            else if (e.Key == hBack) nextValue = FindNextEnabledTab(keys, idx, -1);
        }
        else
        {
            if (e.Key == "ArrowDown") nextValue = FindNextEnabledTab(keys, idx, 1);
            else if (e.Key == "ArrowUp") nextValue = FindNextEnabledTab(keys, idx, -1);
        }
        if (e.Key == "Home") nextValue = keys.FirstOrDefault(k => !IsTabDisabled(k));
        else if (e.Key == "End") nextValue = keys.LastOrDefault(k => !IsTabDisabled(k));

        if (nextValue is not null && Context.TabIds.TryGetValue(nextValue, out var ids))
        {
            // Automatic: arrow keys both activate and move focus.
            // Manual: arrow keys only move focus — the user presses Enter/Space
            // (handled below, or via the button's native click) to activate.
            if (Context.Activation == Tabs.TabsActivation.Automatic)
            {
                await Context.SetValue.InvokeAsync(nextValue);
            }
            await Interop.FocusElement(ids.TabId);
            return;
        }

        // Manual activation: Enter/Space activates the currently focused tab.
        // (In Automatic mode the focused tab is already active, so this is a
        // harmless no-op; the native button click also covers mouse/Space.)
        if ((e.Key == "Enter" || e.Key == " " || e.Key == "Spacebar") && Context.Activation == Tabs.TabsActivation.Manual)
        {
            await Context.SetValue.InvokeAsync(Value);
        }
    }

    private bool IsTabDisabled(string value) =>
        Context.TabIds.TryGetValue(value, out var ids) && ids.Disabled;

    private string? FindNextEnabledTab(List<string> keys, int currentIdx, int direction)
    {
        // Despite its name, this previously returned the next tab UNCHECKED —
        // arrow keys focused AND activated disabled tabs. Walk until an
        // enabled tab is found; null when every other tab is disabled.
        if (keys.Count == 0) return null;
        var idx = currentIdx;
        for (var i = 0; i < keys.Count; i++)
        {
            idx += direction;
            if (idx < 0) idx = keys.Count - 1;
            else if (idx >= keys.Count) idx = 0;
            if (idx == currentIdx) return null;
            if (!IsTabDisabled(keys[idx])) return keys[idx];
        }
        return null;
    }
}
